import React, { Component } from 'react';
import algoliasearch from 'algoliasearch/lite';
import { InstantSearch, SearchBox, Hits, connectHits, connectInfiniteHits, InfiniteHits } from 'react-instantsearch-dom';
import { GoogleMapsLoader, GeoSearch, Marker, Control } from 'react-instantsearch-dom-maps';


import './App.css';


const searchClient = algoliasearch('43H3UXBYSV', '773c0bceb7c1762989f544586f92f65f');


const infiniteHits = ({ hits, refine }) => (
    <div>
        {hits.map(hit => (
            <div key={hit.objectID}>
                {hit.display? <div><h2>{hit.property_name}</h2><p>Contact phone: <a href={"tel:"+hit.contact_number}>{hit.contact_number}</a></p><p>Contact email: <a href={"mail-to:"+hit.contact_email}>{hit.contact_email}</a></p><p>Address:
                    <br/>
                    <i>{hit.address.linel}, {hit.address.locality}, {hit.address.state}, {hit.address.postal_code}</i>
                </p><p>Pet policy status: {hit.pet_policy}</p><p>Website: <a href={hit.website} target="_blank">{hit.website}</a></p></div>:''}
            </div>
        ))}
        <button className="show-more" onClick={refine}>Show more</button>
    </div>
);
const CustomInfiniteHits = connectInfiniteHits(infiniteHits);

const FrontPage = () => (
    <div className="container">
        <InstantSearch searchClient={searchClient} indexName="Housing">
            <div className="row">
                <div className="col">
                    <SearchBox />
                    <CustomInfiniteHits />
                </div>
                <div style={{ height: 500 }} className='col'>
                    <GoogleMapsLoader apiKey="AIzaSyBah20fW-PaxEEUXf7CrZGPp95PusGIL4A">
                        {google => (
                            <GeoSearch
                                google={google}
                            >
                                {({ hits }) => (
                                    <div>
                                        {hits.map(hit => hit.display? <Marker key={hit.objectID} hit={hit}/> : '')}
                                    </div>
                                )}
                            </GeoSearch>
                        )}
                    </GoogleMapsLoader>
                </div>
            </div>
        </InstantSearch>
    </div>
);




export default FrontPage;
